import fs from "node:fs";

// Smoke test: garante que o PDF foi gerado e tem um tamanho mínimo.
export function assertPdf(path) {
  if (!fs.existsSync(path)) throw new Error("PDF não encontrado");
  const size = fs.statSync(path).size;
  if (size < 10_000) throw new Error(`PDF pequeno demais: ${size} bytes`);
  return { ok: true, size };
}
